import{_ as a,o as t,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"115. Higher Duties Allowance","description":"","frontmatter":{"title":"115. Higher Duties Allowance","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","allowances","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/allowances/115-higher-duties-allowance.md","filePath":"ebas/mental-health/health-professionals/allowances/115-higher-duties-allowance.md"}'),s={name:"ebas/mental-health/health-professionals/allowances/115-higher-duties-allowance.md"};function l(n,e,r,h,c,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_115-higher-duties-allowance" tabindex="-1">115. Higher Duties Allowance <a class="header-anchor" href="#_115-higher-duties-allowance" aria-label="Permalink to &quot;115. Higher Duties Allowance&quot;">​</a></h1><p><strong>115.1</strong> Entitlement</p><p><strong>(a)</strong> An Employee who is formally engaged in writing:</p><p><strong>(i)</strong> in any one day or shift for more than two hours in a shift leader (however titled) role; or</p><p><strong>(ii)</strong> to assume the duties of another Employee on a higher classification carrying a higher rate than the classification in which they is ordinarily employed shall be paid for the full day or shift at the minimum rate for that higher classification at the equivalent classification within <a href="/eba/ebas/mental-health/schedules/03-role-statement-mental-health-clinical-educator.html">Schedule 3</a> but if so engaged for two hours or less only the time so worked shall be paid for at that higher rate.</p><p><strong>(b)</strong> This clause does not apply where an employer issues a reasonable direction to an Employee to undertake additional duties in accordance with their existing classification.</p>',6)])])}const g=a(s,[["render",l]]);export{u as __pageData,g as default};
